UPDATE waiting_queue
SET queue_length = #{queueLength},
    queue_status = #{queueStatus}
WHERE queue_id = #{queueId}

UPDATE charging_queue
SET current_length = #{currentLength}
WHERE queue_id = #{queueId}

mapper.insert:
INSERT INTO tariff_policy (
    policy_id, status, peak_price, flat_price, valley_price, service_fee_per_kwh, update_time
) VALUES (
    #{policyId}, #{status}, #{peakPrice}, #{flatPrice}, #{valleyPrice}, #{serviceFeePerKwh}, #{updateTime}
)
ON DUPLICATE KEY UPDATE
    status = #{status},
    peak_price = #{peakPrice},
    flat_price = #{flatPrice},
    valley_price = #{valleyPrice},
    service_fee_per_kwh = #{serviceFeePerKwh},
    update_time = #{updateTime}
